function quizAnswers(answers) { return answers.length === 3 ? [...answers, fourthQuizOption[answers[0]] || 'Det beror på hur uppgiften tolkas'] : answers; }
function showChapter(id) {
  const c = chapters.find(chapter => chapter.id === id); if (!c) return;
  el('#lesson-content').innerHTML = `<div class="lesson-header"><div><p class="eyebrow">Kapitel ${c.nr}</p><h2>${c.title}</h2><p>${c.desc}</p></div><a class="button" href="${presentationPath(c)}">Öppna presentation</a></div><article class="lesson-block"><h3>Efter kapitlet kan du</h3><ul>${c.goals.map(goal => `<li>${goal}</li>`).join('')}</ul></article><article class="lesson-block quick-quiz"><h3>Kapitelquiz: snabbkoll och repetition</h3><div class="lesson-text"><p>Svara utan att titta i materialet. Detta är inte ett prov och sparas bara på din egen enhet. Resultatet visar vilka avsnitt du ska repetera. Gör sedan quizet igen efter repetition och en gång till om 2–3 dagar.</p></div><form class="quiz" data-quiz="${c.id}">${c.quiz.map(([q,answers],i) => `<div class="quiz-question"><p>${i+1}. ${q}</p>${quizAnswers(answers).map((answer,j) => `<label class="options"><span><input type="radio" name="q${i}" value="${j}"> ${answer}</span></label>`).join('')}</div>`).join('')}<button class="button primary" type="submit">Rätta quizet och se vad du ska repetera</button><div class="quiz-result" aria-live="polite"></div></form><p class="presentation-link"><a href="${presentationPath(c)}">Presentation: ${c.title}</a></p></article><div class="lesson-grid"><div>${c.sections.map(([heading, body]) => `<article class="lesson-block"><h3>${heading}</h3><div class="lesson-text">${body}</div></article>`).join('')}<article class="lesson-block"><h3>Genomarbetat exempel</h3><p class="worked-example"><strong>Exempel:</strong> ${c.example}</p></article><article class="lesson-block reflection"><h3>Metakognition: stanna upp</h3><p><strong>Före:</strong> Vad kan jag redan? <strong>Under:</strong> Vilket steg är svårt? <strong>Efter:</strong> Vad behöver jag repetera om två dagar?</p></article></div></div>`;
  if (c.sourceNote) { el('#lesson-content').querySelector('.lesson-header').insertAdjacentHTML('afterend', `<details class="lesson-block source-note"><summary>Forskning och utgångspunkt</summary><div class="lesson-text">${c.sourceNote}</div></details>`); }
  if (c.curriculumNote) { const insertAfter = c.sourceNote ? el('#lesson-content .source-note') : el('#lesson-content .lesson-header'); insertAfter.insertAdjacentHTML('afterend', `<details class="lesson-block source-note"><summary>Koppling till grundskolans kursplan</summary><div class="lesson-text">${c.curriculumNote}</div></details>`); }
  if (c.solSources) { const notes=el('#lesson-content').querySelectorAll('.source-note'); const insertAfter=notes[notes.length-1] || el('#lesson-content .lesson-header'); insertAfter.insertAdjacentHTML('afterend', `<details class="lesson-block source-note"><summary>Fördjupning: SoL-källor för lärare</summary><div class="lesson-text">${c.solSources}</div></details>`); }
  if (c.researchExtension) { el('#lesson-content').querySelector('.lesson-grid > div').insertAdjacentHTML('beforeend', c.researchExtension); }
  if (!isChapterPage()) location.hash='lesson';
}
function gradeQuiz(form) { const c=chapters.find(chapter=>chapter.id===form.dataset.quiz); const output=form.querySelector('.quiz-result'); const unanswered=c.quiz.some((_,i)=>!form.querySelector(`input[name="q${i}"]:checked`)); if(unanswered) { output.innerHTML=`<p class="quiz-feedback error">Svara på alla ${c.quiz.length} frågor först.</p>`; return; } let score=0; const feedback=[]; const repeat=[]; c.quiz.forEach(([,,correct,explanation],i)=>{ const right=+form.querySelector(`input[name="q${i}"]:checked`).value===correct; if(right) score++; else { const section=c.sections[Math.min(i,c.sections.length-1)]; repeat.push(section ? section[0].replace(/^\d+\. /,'') : 'det aktuella begreppet'); } feedback.push(`<li>${right?'Rätt':'Repetera'}: ${explanation}</li>`); }); const uniqueRepeat=[...new Set(repeat)]; const next=score === c.quiz.length ? '<p><strong>Nästa steg:</strong> Bra. Gå vidare eller gör samma quiz igen om 2–3 dagar utan stöd.</p>' : `<p><strong>Repetera nu:</strong> ${uniqueRepeat.join(' · ')}. Läs den korta sammanfattningen, gör en övning och rätta sedan quizet igen.</p>`; localStorage.setItem(`teknik-quiz-${c.id}`,score); output.innerHTML=`<div class="quiz-feedback"><strong>${score} av ${c.quiz.length} rätt.</strong>${next}<ul>${feedback.join('')}</ul></div>`; }
function setupPlan() { const form=el('#plan-form'); const saved=JSON.parse(localStorage.getItem('teknik-plan')||'null'); if(saved) Object.entries(saved).forEach(([key,value])=>form.elements[key].value=value); form.addEventListener('submit',e=>{e.preventDefault(); const plan=Object.fromEntries(new FormData(form)); localStorage.setItem('teknik-plan',JSON.stringify(plan)); const r=el('#plan-result'); r.className='result show'; r.innerHTML=`<strong>Planen är sparad.</strong><br>Du tränar på <em>${escapeHTML(plan.focus)}</em> – ${escapeHTML(plan.when)}. Bevis på lärande: ${escapeHTML(plan.evidence)}.`; }); }

document.addEventListener('DOMContentLoaded',()=>{ const brand=el('.brand'); if (brand) brand.innerHTML='Förkunskaper<br>för teknik och IT'; document.title=document.title.replace('Förkunskaper för teknik','Förkunskaper för teknik och IT'); renderNavigation(); if (el('#chapter-grid')) { renderChapters(); setupPlan(); } if (document.body.dataset.chapter) showChapter(document.body.dataset.chapter); document.addEventListener('submit',event=>{ if(event.target.matches('.quiz')) { event.preventDefault(); gradeQuiz(event.target); } }); const menu=el('.menu-button'); if (menu) menu.addEventListener('click',()=>{ const sidebar=el('#sidebar'); const open=sidebar.classList.toggle('open'); menu.setAttribute('aria-expanded',open); }); });
